export type OrderStatus = "active" | "archived";

export type OrderRecord = {
  id: string;
  orderNumber: string;
  status: OrderStatus;
  customerId?: string | null;
};

export function formatOrderLabel(order: Pick<OrderRecord, "orderNumber" | "status">): string {
  const label = `Order ${order.orderNumber}`;
  return order.status === "archived" ? `${label} (archived)` : label;
}

import { joinNonEmpty } from "../shared/stringUtils.ts";

export type CustomerRecord = {
  id: string;
  givenName?: string;
  familyName?: string;
  companyName?: string;
};

export function formatCustomerDisplayName(customer: CustomerRecord): string {
  return customer.companyName?.trim() || joinNonEmpty([customer.givenName, customer.familyName]) || `Customer ${customer.id}`;
}

import { formatCustomerDisplayName, type CustomerRecord } from "../customers/customerFormatter.ts";
import { formatOrderLabel, type OrderRecord } from "./orderFormatter.ts";

export type OrderView = OrderRecord & {
  label: string;
  displayName: string;
  customer?: CustomerRecord;
};

const customersById = new Map<string, CustomerRecord>([
  ["cust-1", { id: "cust-1", givenName: "Ada", familyName: "Lovelace" }],
  ["cust-2", { id: "cust-2", companyName: "Northwind Traders" }]
]);

const orders: OrderRecord[] = [
  { id: "ord-active", orderNumber: "ORD-1001", status: "active", customerId: "cust-1" },
  { id: "ord-missing-customer", orderNumber: "ORD-1002", status: "active", customerId: "missing-customer" },
  { id: "ord-archived", orderNumber: "ORD-1003", status: "archived", customerId: "cust-2" }
];

export function listOrders(): OrderView[] {
  return orders.map(toOrderView);
}

export function getOrderById(orderId: string): OrderView | undefined {
  const order = orders.find((candidate) => candidate.id === orderId);
  return order ? toOrderView(order) : undefined;
}

function toOrderView(order: OrderRecord): OrderView {
  const customer = order.customerId ? customersById.get(order.customerId) : undefined;
  const label = formatOrderLabel(order);
  const displayName = order.status === "archived" || !customer ? label : `${label} - ${formatCustomerDisplayName(customer)}`;

  return {
    ...order,
    customer,
    label,
    displayName
  };
}

export function joinNonEmpty(parts: Array<string | null | undefined>, separator = " "): string {
  return parts
    .map((part) => part?.trim() ?? "")
    .filter((part) => part.length > 0)
    .join(separator);
}

import assert from "node:assert/strict";
import { describe, it } from "node:test";

import { getOrderById } from "../orderService.ts";

describe("order service display names", () => {
  it("formats an active order with the existing customer display label", () => {
    const order = getOrderById("ord-active");

    assert.equal(order?.displayName, "Order ORD-1001 - Ada Lovelace");
  });

  it("falls back to the existing order label when customer information is missing", () => {
    const order = getOrderById("ord-missing-customer");

    assert.equal(order?.displayName, "Order ORD-1002");
  });

  it("keeps archived orders on the legacy order display text", () => {
    const order = getOrderById("ord-archived");

    assert.equal(order?.displayName, "Order ORD-1003 (archived)");
  });
});

